head.script:
//==================================================================================================================
// id       : zz_620_01_09b
// 이름     : 내부사용자 입/퇴사 관리
// 경로     : 공통/시스템관리/사용자/
// 작 성 자 : 오영재
// 작 업 일 : 2025-12-04
// 사용계정 : 내부
// 비고     :
//
// 업로드   :
// 다운로드 : 
// 레포트   :
// 호출     : 
//==================================================================================================================
// 전역 변수
scwin.memJson = $c.data.getMemInfo();
scwin.userId = scwin.memJson.userId;
scwin.userNm = scwin.memJson.userNm;
scwin.acctDeptCd = scwin.memJson.acctDeptCd;
scwin.acctDeptNm = scwin.memJson.acctDeptNm;
scwin.dateStr     = $c.date.getServerDateTime("yyyyMMdd");	

//hidden
scwin.upperAcctDeptCd;
scwin.itYn;
scwin.loginDept;

scwin.onpageload = function() {
    //f_Header();

    //scwin.upperAcctDeptCd = ds_osideUserMgntWindowOepnInformation.getCellData(0,"upDeptPosNo");

    scwin.loginDept = scwin.acctDeptCd;

    const codeOptions = [
        { grpCd : "ZZ056", compID : "lc_retrievePrgsSts, lc_prgsSts, gr_osideUserMgnt:prgsSts"},
        { grpCd : "ZZ009", compID : "lc_debisUseSyscd"}
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function() {

    //ds_condition.UseChangeInfo = false;
    //tr_search2.post();
    //tr_search2는 사용하지 않는듯
    dma_condition.set("retrieveName", ed_retrieveName.getValue());
    dma_condition.set("retrieveReqDeptCd", ed_retrieveReqDeptCd.getValue());
    dma_condition.set("retrievePrgsSts", lc_retrievePrgsSts.getValue());
    dma_condition.set("registYn", lc_registYn.getValue());
    dma_condition.set("upperAcctDeptCd", scwin.upperAcctDeptCd);
    dma_condition.set("itYn", scwin.itYn);
    dma_condition.set("loginDept", scwin.loginDept);
    $c.sbm.execute(sbm_search2);

    scwin.f_firstSetting();

}


scwin.ondataload = function () {

   if( scwin.acctDeptCd != "00008"){	// IT전략팀이 아니라면

        // 상태구분 셋팅
        if(ds_osideUserMgntWindowOepnInformation.getCellData(0,"deptcapGbn") == 'V1202'){	// 부서장 이라면
            lc_retrievePrgsSts.setSelectedIndex(3);	// 승인요청 으로 셋팅 
        }
        else if(ds_osideUserMgntWindowOepnInformation.getCellData(1,"deptcapGbn") == 'V1201'){	// 부서원 이라면
            lc_retrievePrgsSts.setSelectedIndex(0);	// 전체로 셋팅 
        }

        // 요청부서 셋팅
        ed_retrieveReqDeptCd.setValue(scwin.acctDeptCd);
        ed_retrieveDeptNm.setValue(scwin.acctDeptNm);
        scwin.itYn = 0 ;
    }

    else if(scwin.acctDeptCd == "00008"){	// IT전략팀 이라면
        lc_retrievePrgsSts.setSelectedIndex(4);	// 상태구분 승인 으로 셋팅
        scwin.itYn = 1 ;
    }	
};




//-------------------------------------------------------------------------
// Enable/Disable
//-------------------------------------------------------------------------
scwin.f_firstSetting = function(){
    $c.gus.cfDisableKeyData();			 
    //cfDisableObjects([lc_acctCd,txt_acctDeptNm])	
    //$c.gus.cfDisableObjects([ed_reqDeptNm, ed_enterDt, img_resignDt, img_debisAcctDeptNm, img_clntNm, img_deptNm1, img_jikGubNm, img_jikwiNm, img_name2, img_name3]); 
    $c.gus.cfDisableObjects(tbl1);
    $c.gus.cfDisableObjects(tbl2);
    $c.gus.cfDisableObjects([btn_create, btn_update, btn_cancel, btn_delete, btn_save1, btn_save2, btn_save3, btn_save4, btn_save5]);
    $c.gus.cfEnableObjects([ed_retrieveName, ed_retrieveReqDeptCd, ed_retrieveDeptNm]);	 
    //disabledKey에 걸림
    $c.gus.cfEnableObjects([lc_retrievePrgsSts, lc_registYn]);	 
}	

//-------------------------------------------------------------------------
// 온클릭, 취소 이벤트
//-------------------------------------------------------------------------
scwin.f_eventOnClick = function(){

    if(ds_osideUserMgnt.getRowCount() == 0)
    {	
        // 조회 결과가 없어
        $c.win.alert("조회 결과가 없습니다.");
        $c.gus.cfDisableObjects([btn_update, btn_delete, btn_save1, btn_save2, btn_save3, btn_save4, btn_save5]);
        $c.gus.cfEnableObj(btn_create, true);
    }

    else	
    {	

        // 조회 결과가 한 줄 이상이 나오네
//alert("scwin.acctDeptCd =>" + scwin.acctDeptCd);
//scwin.acctDeptCd = "00008";
        if( scwin.acctDeptCd == '00008')
        {	// IT전략팀 이라면 모든 버튼 활성화
            $c.gus.cfEnableObjects([btn_create, btn_delete, btn_update, btn_save1, btn_save2, btn_save3, btn_save4, btn_save5]);
        }

        else if( scwin.acctDeptCd != '00008' && ds_osideUserMgntWindowOepnInformation.getCellData(0,"deptcapGbn") == 'V1202')
        {	// 부서장 이라면
            if(ds_osideUserMgnt.getCellData(0,"admitSabun") == scwin.userId)
            {
                if(lc_prgsSts.getSelectedIndex() == 3){
                    $c.gus.cfEnableObjects([btn_cancel, btn_save2, btn_save4, ed_rejectRsn]);
                }
                else{
                    $c.gus.cfEnableObjects([btn_cancel]);
                }
            }
        }

        else if( scwin.acctDeptCd != '00008' && ds_osideUserMgntWindowOepnInformation.getCellData(0,"deptcapGbn") == 'V1201')
        {	// 등록자 이라면
            if(ds_osideUserMgnt.getCellData(0,"reqSabun") == scwin.userId)
            {
                if(lc_prgsSts.getSelectedIndex() == 1){	// 신규인 경우
                    $c.gus.cfEnableObjects([btn_create, btn_update, btn_cancel, btn_delete, btn_save1]);
                }
                if(lc_prgsSts.getSelectedIndex() == 2){	// 변경인 경우
                    $c.gus.cfEnableObjects([btn_create, btn_update, btn_cancel, btn_save1]);
                }
                if(lc_prgsSts.getSelectedIndex() == 3){	// 승인요청
                    $c.gus.cfEnableObjects([btn_create, btn_update, btn_cancel]);
                }
                if(lc_prgsSts.getSelectedIndex() == 4){	// 승인인 경우
                    $c.gus.cfEnableObjects([btn_create]);
                }
                if(lc_prgsSts.getSelectedIndex() == 5 || lc_prgsSts.getSelectedIndex() == 6 || lc_prgsSts.getSelectedIndex() == 7){	// 반려, 최종반려, 최종승인인 경우
                    $c.gus.cfEnableObjects([btn_create, btn_cancel, btn_update]);
                }
            }
        }

        else
        {
            $c.gus.cfEnableObjects([btn_create]);
        }
    }

    if(lc_prgsSts.getSelectedIndex() == 4)	// 승인 상태인 경우
    {
        $c.gus.cfDisableObjects([btn_update, btn_delete, btn_save1, btn_save2, btn_save5]);
    }

    if(lc_prgsSts.getSelectedIndex() == 7)	// 승인 상태인 경우
    {
        $c.gus.cfDisableObjects([btn_cancel, btn_save1, btn_save2, btn_save3]);
    }
}

//-------------------------------------------------------------------------
// 신규 버튼 클릭시
//-------------------------------------------------------------------------	
scwin.f_Create = function() {
    let row;
    row = ds_osideUserMgnt.insertRow();
    ds_osideUserMgnt.setRowPosition(row);
    gr_osideUserMgnt.setFocusedCell(row, 0, false);

    $c.gus.cfEnableObjects([ed_shrDeptCd, ed_deptNm1, ed_enterDt, ed_name, ed_reqDeptCd, btn_deptNm2, ed_deptNm2, chb_debisUseYn, chb_porteUseYn, ed_reqSabun, ed_name2, btn_name2, ed_reqRsn, btn_name3]);
    $c.gus.cfEnableObjects([btn_cancel, btn_save5, btn_deptNm1, ed_admitSabun, ed_name3, btn_name3]);

    lc_prgsSts.setSelectedIndex(1);

    ed_reqSabun.setValue( ds_osideUserMgntWindowOepnInformation.getCellData(0,"sabun") );
    ed_name2.setValue( ds_osideUserMgntWindowOepnInformation.getCellData(0,"name") );
    ed_reqDeptCd.setValue( scwin.acctDeptCd );
    ed_deptNm2.setValue( scwin.acctDeptNm );
    ed_admitSabun.setValue( ds_osideUserMgntWindowOepnInformation.getCellData(0,"capSabun") );
    ed_name3.setValue( ds_osideUserMgntWindowOepnInformation.getCellData(0,"capName") );

    ed_reqDt.setValue( scwin.dateStr );
    ed_firstRegistDt.setValue( scwin.dateStr );
}     

//-------------------------------------------------------------------------
// 수정 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_Update = function(){
    let row = ds_osideUserMgnt.getRowPosition();
    if(ds_osideUserMgnt.getCellData(row,"prgsSts") == '6'){
        //alert("상태구분이 최종승인인 건은 수정 불가능 합니다.");
        //return;
    }

    if(ds_osideUserMgnt.getCellData(row,"prgsSts") != '1'){
        if(ds_osideUserMgnt.getCellData(row,"resignDt") != ''){
            $c.win.alert("퇴사한 사원 정보는 수정 불가능 합니다.");
            return;
        }
    }

    if(lc_prgsSts.getSelectedIndex() == 1)	// 신규 상태에서 수정 버튼을 누른 경우 상태구분은 신규로 고정
    {	
        $c.gus.cfEnableObjects([ed_shrDeptCd, ed_deptNm1, btn_deptNm1, ed_name, ed_reqDeptCd, btn_deptNm2, ed_deptNm2, chb_debisUseYn, chb_porteUseYn, ed_enterDt, ed_reqSabun, ed_name2, btn_name2, ed_reqRsn, btn_name3]);
        $c.gus.cfEnableObjects([btn_cancel, btn_save5, ed_enterDt, ed_admitSabun, ed_name3, btn_name3]);
        $c.gus.cfDisableObjects([btn_update]);

        scwin.f_checkdebisUseYn();
        scwin.f_checkPorteUseYn();

        ed_reqDt.setValue (scwin.dateStr);

        lc_prgsSts.setSelectedIndex(1);	
    }

    else if(lc_prgsSts.getSelectedIndex() == 2 || lc_prgsSts.getSelectedIndex() == 3)	// 변경, 승인요청 상태인 경우
    {
        $c.gus.cfEnableObjects([ed_shrDeptCd, ed_deptNm1, btn_deptNm1, ed_name, ed_reqDeptCd, btn_deptNm2, ed_deptNm2, chb_debisUseYn, chb_porteUseYn, ed_enterDt, ed_reqSabun, ed_name2, btn_name2, ed_reqRsn, btn_name3]);
        $c.gus.cfEnableObjects([btn_cancel, btn_save5, ed_admitSabun, ed_name3, btn_name3]);
        $c.gus.cfDisableObjects([btn_update]);

        scwin.f_checkdebisUseYn();
        scwin.f_checkPorteUseYn();

        ed_reqSabun.setValue( ds_osideUserMgntWindowOepnInformation.getCellData(0,"sabun") );
        ed_name2.setValue( ds_osideUserMgntWindowOepnInformation.getCellData(0,"name") );
        ed_admitSabun.setValue( ds_osideUserMgntWindowOepnInformation.getCellData(0,"capSabun") );
        ed_name3.setValue( ds_osideUserMgntWindowOepnInformation.getCellData(0,"capName") );
        ed_reqDt.setValue( scwin.dateStr );

        lc_prgsSts.setSelectedIndex(4);	
    }

    else if(lc_prgsSts.getSelectedIndex() == 4)	// 승인 상태인 경우
    {
        $c.gus.cfDisableObjects([btn_update, btn_delete, btn_save5]);
    }

    else if(lc_prgsSts.getSelectedIndex() == 5 || lc_prgsSts.getSelectedIndex() == 6){	// 반려, 최종반려 인 경우
        $c.gus.cfEnableObjects([ed_shrDeptCd, ed_deptNm1, ed_name, ed_enterDt, ed_resignDt, ed_reqSabun, ed_name2, btn_name2, ed_reqRsn, chb_debisUseYn, chb_porteUseYn]);
        $c.gus.cfEnableObjects([btn_deptNm1, btn_name2, ed_admitSabun, ed_name3, btn_save5, btn_name3]);

        scwin.f_checkdebisUseYn();
        scwin.f_checkPorteUseYn();

        ed_reqSabun.setValue( ds_osideUserMgntWindowOepnInformation.getCellData(0,"sabun") );
        ed_name2.setValue( ds_osideUserMgntWindowOepnInformation.getCellData(0,"name") );
        ed_admitSabun.setValue( ds_osideUserMgntWindowOepnInformation.getCellData(0,"capSabun") );
        ed_name3.setValue( ds_osideUserMgntWindowOepnInformation.getCellData(0,"capName") );
        ed_reqDt.setValue(  scwin.dateStr );
        ed_reqDeptCd.setValue( scwin.acctDeptCd );
        ed_deptNm2.setValue( scwin.acctDeptNm );

        lc_prgsSts.setSelectedIndex(2);	
    }

    else if(lc_prgsSts.getSelectedIndex() == 7){	// 최종승인 상태인 경우
        //cfEnableObjects([ed_resignDt, img_resignDt, btn_save5, txt_reqRsn, btn_cancel]);
        //cfDisableObjects([btn_create, btn_update, btn_delete, btn_save2, btn_save3, btn_save4, btn_save1]);

        $c.gus.cfEnableObjects([ed_resignDt, ed_shrDeptCd, ed_deptNm1, btn_deptNm1, ed_name, ed_reqDeptCd, btn_deptNm2, ed_deptNm2, chb_debisUseYn, chb_porteUseYn, ed_enterDt, ed_reqSabun, ed_name2, btn_name2, ed_reqRsn, btn_name3]);
        $c.gus.cfEnableObjects([btn_cancel, btn_save5, ed_admitSabun, ed_name3, btn_name3]);//btn_resignDt 없음
        $c.gus.cfDisableObjects([btn_update]);

        scwin.f_checkdebisUseYn();
        scwin.f_checkPorteUseYn();

        ed_reqSabun.setValue( ds_osideUserMgntWindowOepnInformation.getCellData(0,"sabun") );
        ed_name2.setValue( ds_osideUserMgntWindowOepnInformation.getCellData(0,"name") );
        ed_reqDt.setValue( scwin.dateStr );
        ed_finalAdmitSabun.setValue("");
        ed_name4.setValue("");
        ed_finalAdmitDt.setValue("");
        lc_prgsSts.setSelectedIndex(4);	
    }
}  

//-------------------------------------------------------------------------
// 취소 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_Cancel = function() {
    //ds_osideUserMgnt.undoRow( ds_osideUserMgnt.getRowPosition() );
    //$c.data.undoRow(ds_osideUserMgnt,"Y"); 

    var rP = ds_osideUserMgnt.getRowPosition();
    ds_osideUserMgnt.undoRow(ds_osideUserMgnt.getRowPosition());
    if(ds_osideUserMgnt.getRowStatus(rP) == 'C' ){
        ds_osideUserMgnt.removeRow(rP);//delete는 남는다.
    }
    $c.gus.cfEnableObjects([btn_create, btn_update]);

    scwin.f_firstSetting();
    scwin.f_eventOnClick();
    $c.gus.cfDisableObjects([btn_cancel]);
}    

//-------------------------------------------------------------------------
// 저장 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_Save5 = async function(){
    if( ds_osideUserMgnt.getModifiedIndex().length < 1){
        $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    if(ed_reqDeptCd.getValue() == ''){
        $c.win.alert("요청 부서는 필수 입력 사항 입니다.");
        ed_reqDeptCd.focus();
        return;
    }

    if(ed_name.getValue() == ''){
        $c.win.alert("성명은 필수 입력 사항 입니다.");
        ed_name.focus();
        return;
    }

    if(ed_enterDt.getValue() == ''){
        $c.win.alert("입사일은 필수 입력 사항 입니다.");
        ed_enterDt.focus();
        return;
    }

    if(ed_shrDeptCd.getValue() == ''){
        $c.win.alert("SHR부서는 필수 입력 사항 입니다.");
        ed_shrDeptCd.focus();
        return;
    }

    if(ds_osideUserMgnt.getCellData(ds_osideUserMgnt.getRowPosition(),"debisUseYn") == '1'){
        if(ed_debisAcctDeptCd.getValue() == '' || ed_debisAcctDeptNm.getValue() == ''){
            $c.win.alert("데비스 사용 선택시 귀속부서는 필수 입력 입니다.");
            return;
        }
    }	
    if(ds_osideUserMgnt.getCellData(ds_osideUserMgnt.getRowPosition(),"porteUseYn") == '1'){
        if(ed_shrJikGubCd.getValue() == '' || ed_jikGubNm.getValue() == ''){
            $c.win.alert("포르테 사용 선택시 직급은 필수 입력 입니다.");
            return;
        }
        else if(ed_shrJikWiCd.getValue() == '' || ed_jikwiNm.getValue() == ''){
            $c.win.alert("포르테 사용 선택시 직위는 필수 입력 입니다.");
            return;
        }
        else if(ed_porteReqId.getValue() == ''){
            $c.win.alert("포르테 사용 선택시 포르테신청ID는 필수 입력 입니다.");
            return;
        }
    }
    if(ed_reqSabun.getValue() == ''){
        $c.win.alert("요청자는 필수 입력 사항 입니다.");
        ed_reqSabun.focus();
        return;
    }

    if(ed_reqRsn.getValue() == ''){
        $c.win.alert("요청사유는 필수 입력 사항 입니다.");
        ed_reqRsn.focus();
        return;
    }

    if(ed_admitSabun.getValue() == ''){
        $c.win.alert("승인자는 필수 입력 사항 입니다.");
        ed_admitSabun.focus();
        return;
    }

    if(lc_prgsSts.getSelectedIndex() == 2){	// 변경인 경우
        if(ed_resignDt.getValue() == ''){
            //alert("수정시 퇴사일은 필수 입력 사항 입니다.");
            //return;
        }
    }

    let ret;
    ret = await $c.gus.cfValidate([gr_osideUserMgnt]);
    if (ret) {

        ret = await $c.win.confirm(MSG_CM_CRM_001);
        if(ret == true){
            //tr_save.Post();     
            scwin.setNameByByteLength(); 
            $c.sbm.execute(sbm_save);
        }
    }
}   

scwin.sbm_save_submitdone = async function(e) {
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
        scwin.f_Retrieve();
    }
}

scwin.sbm_save_submiterror = function(e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);   
}

//-------------------------------------------------------------------------
// 삭제 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_Delete = async function() {
    if(ds_osideUserMgnt.getCellData(ds_osideUserMgnt.getRowPosition(),"prgsSts") != '0'){
        $c.gus.cfAlertMsg("상태구분이 신규인 건만 삭제 가능 합니다.");
        return;
    }

    ds_osideUserMgnt.setCellData(ds_osideUserMgnt.getRowPosition(),"delYn", "1");  
    ds_osideUserMgnt.deleteRow(ds_osideUserMgnt.getRowPosition()); 

    let ret;
    ret = await $c.win.confirm("삭제 하시겠습니까?");
    if(ret == true){
        //tr_save.Post();
        $c.sbm.execute(sbm_save);
    }
}  

//-------------------------------------------------------------------------
// 승인요청 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_Save1 = async function() {
    let row = ds_osideUserMgnt.getRowPosition();
    if(ds_osideUserMgnt.getCellData(row,"prgsSts") != '0' && ds_osideUserMgnt.getCellData(row,"prgsSts") != '1'){
        $c.gus.cfAlertMsg("상태구분이 신규 및 변경인 건만 승인요청 가능 합니다.");
        return;
    }

    if((ds_osideUserMgnt.getCellData(row,"reqSabun")) != scwin.userId){
        //alert("요청자와 로그인 사용자가 다른 경우 승인 요청이 불가능 합니다.");
        //return;
    }

    lc_prgsSts.setSelectedIndex(3);
    let ret;
    ret = await $c.win.confirm("승인요청 하시겠습니까?");
    if( ret == true){
        //tr_save.Post(); 
        scwin.setNameByByteLength();
        $c.sbm.execute(sbm_save);
    }
}   

//-------------------------------------------------------------------------
// 부서장승인 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_Save2 = async function(){
    let ret;
    ret = await $c.win.confirm("승인처리 하시겠습니까?");
    if(ret == true){
        ed_admitDt.setValue( scwin.dateStr );	// 승인일자 셋팅
        ed_admitSabun.setValue ( scwin.userId );
        ed_name3.setValue ( scwin.userNm );
        lc_prgsSts.setSelectedIndex(4);

        //tr_save.Post();    
        scwin.setNameByByteLength();
        $c.sbm.execute(sbm_save);  
    }
}   

//-------------------------------------------------------------------------
// 최종승인 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_Save3 = async function(){
    if( scwin.acctDeptCd != '00008'){
        $c.win.alert("최종승인은 IT전략팀 고유 권한 입니다.");
        return;
    }

    let ret;
    ret = await $c.win.confirm("최종 승인 하시겠습니까?");
    if(ret == true){
        ed_finalAdmitSabun.setValue(scwin.userId);
        ed_name4.setValue( scwin.userNm );
        ed_finalAdmitDt.setValue( scwin.dateStr );	// 최종승인일자 셋팅
        lc_prgsSts.setSelectedIndex(7);

        //tr_save.Post();     
        scwin.setNameByByteLength();
        $c.sbm.execute(sbm_save);   
    }
}      	  

//-------------------------------------------------------------------------
// 반려 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_Save4 = async function(){
    if(ed_rejectRsn.getValue() == ''){
        $c.win.alert("반려사유를 입력 하셔야 합니다.");
        return;
    }

    let ret;
    ret = await $c.win.confirm("반려처리 하시겠습니까?");
    if(ret == true){
        if( scwin.acctDeptCd != '00008') {
            // 부서장 반려시 반려 처리
            lc_prgsSts.setSelectedIndex(5);
        }
        else{
            // IT전략팀 반려시 최종 반려 처리
            lc_prgsSts.setSelectedIndex(6);
        }
        ed_rejectDt.setValue( scwin.dateStr );	// 반려일자 셋팅
        //tr_save.Post(); 
        scwin.setNameByByteLength();
        $c.sbm.execute(sbm_save);     
    }
}    

