scwin.f_Export = function() {
    if(ds_osideUserMgnt.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    } else {


        let sheetTitle = "내부사용자 입퇴사 관리";
        const gridId = gr_osideUserMgnt;
        const infoArr = [];
        const options = {
            fileName: sheetTitle + ".xlsx",    // + ".xlsx",
            sheetName: sheetTitle,
            type: 2+4+8+16

        };

        $c.data.downloadGridViewExcel(gridId, options, infoArr);
    }
}
