scwin.gr_osideUserMgnt_oncellclick = function (rowIndex, columnIndex, columnId) {


    scwin.f_firstSetting();
	scwin.f_Cancel();
    var Row = rowIndex;

    if(scwin.acctDeptCd == '00008')
    {
    	// IT전략팀 온클릭 이벤트
    	if(lc_prgsSts.getSelectedIndex() == 1){	// 신규인 경우
    		$c.gus.cfEnableObjects([btn_create, btn_update, btn_cancel, btn_delete, btn_save1]);
    	}
    	if(lc_prgsSts.getSelectedIndex() == 2){	// 변경인 경우
    		$c.gus.cfEnableObjects([btn_create, btn_update, btn_cancel, btn_save1, btn_save2, btn_save3]);
    	}
    	if(lc_prgsSts.getSelectedIndex() == 3 || lc_prgsSts.getSelectedIndex() == 4){	// 승인요청, 승인인 경우
    		$c.gus.cfEnableObjects([btn_create, btn_save3, btn_save4, ed_rejectRsn]);
    	}
    	if(lc_prgsSts.getSelectedIndex() == 5 || lc_prgsSts.getSelectedIndex() == 6){	// 반려, 최종반려, 최종승인인 경우
    		$c.gus.cfEnableObjects([ed_rejectRsn, btn_create, btn_save5, btn_cancel, btn_update, btn_save1, btn_save2, btn_save3, btn_save4, btn_save5]);
    	}
    	if(lc_prgsSts.getSelectedIndex() == 7)	// 최종승인 상태인 경우
		{
			$c.gus.cfEnableObjects([ed_rejectRsn, btn_create, btn_save5, btn_update, btn_save3, btn_save4, btn_save5]);
			$c.gus.cfDisableObjects([btn_cancel, btn_save1, btn_save2, btn_save3]);
		}
    }

    else if(scwin.acctDeptCd != '00008' && ds_osideUserMgntWindowOepnInformation.getCellData(0,"deptcapGbn") == 'V1202')
    {
    	// 부서장 온클릭 이벤트
    	if(ds_osideUserMgnt.getCellData(Row,"admitSabun") == scwin.userId)
    	{
	    	if(lc_prgsSts.getSelectedIndex() == 3){
	    		$c.gus.cfEnableObjects([btn_cancel, btn_save2, btn_save4, txt_rejectRsn]);
	    	}
	    	else{
	    		$c.gus.cfEnableObjects([btn_cancel]);
	    	}
    	}
    }

    else if(scwin.acctDeptCd != '00008' && ds_osideUserMgntWindowOepnInformation.getCellData(0,"deptcapGbn") == 'V1201')
    {
    	// 등록자 온클릭 이벤트
    	if(lc_prgsSts.getSelectedIndex() == 1){	// 신규인 경우
    		$c.gus.cfEnableObjects([btn_create, btn_update, btn_cancel, btn_delete, btn_save1]);
    	}
    	if(lc_prgsSts.getSelectedIndex() == 2){	// 변경인 경우
    		$c.gus.cfEnableObjects([btn_create, btn_update, btn_cancel, btn_save1]);
    	}
    	if(lc_prgsSts.getSelectedIndex() == 3){	// 승인요청
	    		$c.gus.cfEnableObjects([btn_create, btn_update, btn_cancel]);
    	}
    	if(lc_prgsSts.getSelectedIndex() == 4){	// 승인인 경우
    		$c.gus.cfEnableObjects([btn_create]);
    	}
    	if(lc_prgsSts.getSelectedIndex() == 5 || lc_prgsSts.getSelectedIndex() == 6 || lc_prgsSts.getSelectedIndex() == 7){	// 반려, 최종반려, 최종승인인 경우
    		$c.gus.cfEnableObjects([btn_create, btn_cancel, btn_update]);
		}
    }

    else
    {
    	$c.gus.cfEnableObjects([btn_create]);
    }

    if(ds_osideUserMgnt.getRowStatus(rowIndex) =='C' || ds_osideUserMgnt.getRowStatus(rowIndex) == 'V'){
        ds_osideUserMgnt.removeRow(rowIndex);
        if(ds_osideUserMgnt.getRowCount()-1 >= rowIndex){
            ds_osideUserMgnt.setRowPosition(rowIndex);
            gr_osideUserMgnt.setFocusedCell(rowIndex, columnIndex, false);
        } else {
            ds_osideUserMgnt.setRowPosition(rowIndex-1);
            gr_osideUserMgnt.setFocusedCell(rowIndex-1, columnIndex, false);
        }
    } else {
        ds_osideUserMgnt.setRowPosition(rowIndex);
        gr_osideUserMgnt.setFocusedCell(rowIndex, columnIndex, false);
    }
};

